INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 40011, 321, 1, 2, 1, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 1, "リリ", 125801, 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 40011, 322, 1, 2, 1, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 2, "クリア", 126001, 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 40011, 323, 1, 2, 1, "んーと。\nこれ、あげる。\nはい", 3, "プレシア", 126101, 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 40011, 324, 1, 2, 2, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 4, "リリ", 125801, 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 40011, 325, 1, 2, 2, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 5, "クリア", 126001, 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (24001, 40011, 326, 1, 2, 2, "お兄。\nきてくれて、うれしい", 6, "プレシア", 126101, 0);
